package com.cora.stylefinder.member.activity;
import com.cora.stylefinder.member.member.User; import jakarta.persistence.*;
@Entity @Table(name="saved_results",uniqueConstraints=@UniqueConstraint(columnNames={"user_id","catalog_item_id"})) public class SavedResult { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) Long id; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="user_id") User user; String catalogItemId,title,imageUrl,sourceUrl; double similarityScore; String modelVersion; @Column(columnDefinition="TEXT") String metadataJson; protected SavedResult(){} public SavedResult(User u,String id,String t,String image,String source,double score,String model,String meta){user=u;catalogItemId=id;title=t;imageUrl=image;sourceUrl=source;similarityScore=score;modelVersion=model;metadataJson=meta;} public Long getId(){return id;} }
